import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";
import BreathingExercise from "../components/BreathingExercise";

import { isCrisisMessage } from "../utils/crisisEngine";
import { crisisReply } from "../utils/aiReplies";
import { analyzeMood, saveMood } from "../utils/moodEngine";

const GeneralChat = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [showBreathing, setShowBreathing] = useState(false);

  // 🧠 conversation memory
  const [lastEmotion, setLastEmotion] = useState(null);
  const [lastTopic, setLastTopic] = useState(null);
  const [waitingForConsent, setWaitingForConsent] = useState(false);

  const chatEndRef = useRef(null);

  useEffect(() => {
    setMessages([
      {
        sender: "ai",
        text: "Hello 👋 I’m really glad you’re here. How are you feeling today?",
      },
    ]);
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // 🧠 Therapist-style reply builder
  const buildTherapistReply = (text, mood) => {
    const acknowledge = "Thank you for sharing that with me 🤍";
    const reflect = `It sounds like you’re feeling ${mood}.`;
    const validate = "It’s completely okay to feel this way.";
    const question =
      mood === "anxious"
        ? "Do you want to tell me what’s making you feel anxious right now?"
        : mood === "sad"
        ? "Would you like to share what’s been weighing on you?"
        : mood === "angry"
        ? "What do you think triggered this feeling?"
        : "Can you tell me a little more about that?";

    return `${acknowledge}\n\n${reflect}\n${validate}\n\n${question}`;
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    const userText = input.toLowerCase();

    setMessages((prev) => [...prev, { sender: "user", text: input }]);
    setInput("");

    // 🚨 CRISIS FLOW (unchanged)
    if (isCrisisMessage(userText)) {
      setMessages((prev) => [
        ...prev,
        { sender: "ai", text: crisisReply() },
      ]);
      setShowBreathing(true);
      return;
    }

    // 🎵 Song request handling
    if (userText.includes("song")) {
      setMessages((prev) => [
        ...prev,
        {
          sender: "ai",
          text: "I’d love to help 💙 What kind of mood do you want the song for — calm, sad, happy, or stress-relief?",
        },
      ]);
      return;
    }

    // 👍 Consent-based suggestions
    if (waitingForConsent) {
      if (userText.includes("yes")) {
        setMessages((prev) => [
          ...prev,
          {
            sender: "ai",
            text:
              "Alright 🤍 Here’s one gentle thing you can try right now:\n\n" +
              "Take a slow breath in for 4 seconds… hold for 4… and exhale for 6.\n" +
              "You don’t need to fix everything — just this moment.",
          },
        ]);
      } else {
        setMessages((prev) => [
          ...prev,
          {
            sender: "ai",
            text:
              "That’s completely okay 💭 I’m here to listen. Tell me more whenever you’re ready.",
          },
        ]);
      }
      setWaitingForConsent(false);
      return;
    }

    // 🧠 NORMAL THERAPIST FLOW
    const moodData = analyzeMood(userText);
    saveMood(moodData);

    setLastEmotion(moodData.mood);
    setLastTopic(userText);

    setTimeout(() => {
      setMessages((prev) => [
        ...prev,
        {
          sender: "ai",
          text: buildTherapistReply(userText, moodData.mood),
        },
        {
          sender: "ai",
          text:
            "Would you like suggestions to help with this, or would you prefer to keep talking about it?",
        },
      ]);
      setWaitingForConsent(true);
    }, 700);
  };

  return (
    <div className="chat-page">
      <div className="chat-card">
        <div className="chat-header">
          <h2>General Chat</h2>
        </div>

        <div className="chat-body">
          {messages.map((msg, i) => (
            <div key={i} className={`chat-bubble ${msg.sender}`}>
              {msg.text}
            </div>
          ))}
          {showBreathing && <BreathingExercise />}
          <div ref={chatEndRef} />
        </div>

        <div className="chat-input">
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type how you feel..."
            onKeyDown={(e) => e.key === "Enter" && handleSend()}
          />
          <button onClick={handleSend}>Send</button>
        </div>
      </div>
    </div>
  );
};

export default GeneralChat;
